ops.insert:
{{- define "fullname" -}}
{{- if .Values.fullnameOverride }}
{{- .Values.fullnameOverride | trunc 63 | trimSuffix "-" }}
{{- else }}
{{- printf "%s" .Release.Name | trunc 63 | trimSuffix "-" }}
{{- end }}
{{- end -}}

data:
  config.yaml: |-
    debug: {{.Values.debug}}
    tenantNsSelector:
      {{- toYaml .Values.tenantNsSelector | trim | nindent 6 }}

    worker:
      joinAddr: {{ $.Values.fixedService.ip }}:{{ $.Values.fixedService.port }}
      {{- toYaml .Values.worker | trim | nindent 6 }}

    probes:
      probeIB:   {{- toYaml .Values.probeIB | trim | nindent 8 }}
      probeVpcNatgw: {{- toYaml .Values.probeVpcNatgw | trim | nindent 8 }}
      probeTenant:   {{- toYaml .Values.probeTenant | trim | nindent 8 }}

kind: Secret
name: {{ template "fullname" . }}-metric-auth
type: Opaque
data:
  user: {{ default "bosonprobe" .Values.serviceMonitor.authUser | b64enc | quote }}
  password: {{ default "bosonprobe" .Values.serviceMonitor.authPass | b64enc | quote }}
